def get_submodule(module, attr_name):
        attrs = attr_name.split(".")
        for attr in attrs:
            if isinstance(module, torch.nn.ModuleList):
                module = module[int(attr)]
            elif isinstance(module, torch.nn.ModuleDict):
                module = module[attr]
            else:
                module = getattr(module, attr)
        return module
